python3 -c 'import sqlite3; conn=sqlite3.connect("/opt/mentor-bot/data/mentor_bot.db"); conn.row_factory=sqlite3.Row; sql1=conn.execute("select sql from sqlite_master where type=\"table\" and name=\"owner_tg_accounts\"").fetchone(); sql2=conn.execute("select sql from sqlite_master where type=\"table\" and name=\"owner_tg_script_settings\"").fetchone(); print(sql1["sql"] if sql1 else "NO owner_tg_accounts"); print(sql2["sql"] if sql2 else "NO owner_tg_script_settings"); rows=conn.execute("select id,title,account_type,api_id,session_file from owner_tg_accounts order by id").fetchall(); print("ACCOUNTS",len(rows)); [print(dict(r)) for r in rows]; cfg=conn.execute("select ai_enabled,ai_auto_enabled,ai_auto_interval_sec from owner_tg_script_settings limit 1").fetchone(); print("CFG",dict(cfg) if cfg else None)'
